import{_ as r,o,c as n,ai as s}from"./chunks/framework.ampVZV4B.js";const h=JSON.parse('{"title":"SpringCloud 微服务架构核心组件","description":"","frontmatter":{},"headers":[],"relativePath":"framework/springcloud-microservice.md","filePath":"framework/springcloud-microservice.md"}'),e={name:"framework/springcloud-microservice.md"};function a(g,t,i,l,d,c){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="springcloud-微服务架构核心组件" tabindex="-1">SpringCloud 微服务架构核心组件 <a class="header-anchor" href="#springcloud-微服务架构核心组件" aria-label="Permalink to “SpringCloud 微服务架构核心组件”">​</a></h1><hr><h3 id="❓-面试官-你们项目用的微服务架构是怎样的-包含哪些核心组件" tabindex="-1">❓ 面试官：你们项目用的微服务架构是怎样的？包含哪些核心组件？ <a class="header-anchor" href="#❓-面试官-你们项目用的微服务架构是怎样的-包含哪些核心组件" aria-label="Permalink to “❓ 面试官：你们项目用的微服务架构是怎样的？包含哪些核心组件？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我们项目采用的是 <strong>Spring Cloud Alibaba</strong> 体系（目前国内最主流）。核心组件包括：<strong>Nacos</strong>（注册中心与配置中心）、<strong>OpenFeign</strong>（服务间远程调用）、<strong>Sentinel</strong>（限流熔断降级）、<strong>Gateway</strong>（API 网关）、以及 <strong>Seata</strong>（分布式事务）。</p><p><strong>📝 各大组件作用通俗解析：</strong></p><ol><li><strong>Nacos（通讯录/大管家）</strong>：以前 A 服务调用 B 服务，A 需要把 B 的 IP 写死在代码里（极度耦合）。现在 B 启动时把自己的 IP 告诉 Nacos；A 想找 B，直接去 Nacos 这个“通讯录”里按名字（服务名）查，动态获取 IP。</li><li><strong>OpenFeign（假装在调本地方法）</strong>：在 A 服务里写一个接口，打上 <code>@FeignClient(&quot;service-B&quot;)</code>。然后在代码里直接像调本地 Service 一样调这个接口，底层它会自动帮你把参数序列化成 HTTP 强求发给 B 服务，极大简化了远程调用代码。</li><li><strong>Gateway（小区保安大门）</strong>：前端 App 不可能记住微服务内部几十个 IP 端口。所有外部请求统一先打到网关，由网关进行统一的 <strong>鉴权（Token 校验）、跨域处理、日志记录</strong>，然后再路由转发给后端的具体微服务。</li><li><strong>Sentinel（保险丝）</strong>：如果 B 服务突然宕机或者巨慢无比，A 还在疯狂调用 B，会导致 A 的线程池也被拖死（服务雪崩）。Sentinel 可以配置：当 B 服务出错率超过 50% 时，直接<strong>熔断</strong>，A 不再去调 B，而是快速返回一个默认的降级数据（如“当前人多拥挤”），保全了 A 服务。</li></ol><hr><h3 id="❓-面试官-能详细说说-nacos-作为注册中心-它的服务发现和心跳机制是怎么样的吗-【中高级】" tabindex="-1">❓ 面试官：能详细说说 Nacos 作为注册中心，它的服务发现和心跳机制是怎么样的吗？【中高级】 <a class="header-anchor" href="#❓-面试官-能详细说说-nacos-作为注册中心-它的服务发现和心跳机制是怎么样的吗-【中高级】" aria-label="Permalink to “❓ 面试官：能详细说说 Nacos 作为注册中心，它的服务发现和心跳机制是怎么样的吗？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Nacos 的服务注册是服务提供者在启动时向 Nacos 发送 REST 请求注册自身信息。为了保证服务高可用，Nacos 引入了<strong>客户端定时发送心跳包</strong>以及<strong>服务端主动剔除不健康节点</strong>的机制，同时通过 <strong>UDP 推送 + 客户端轮询</strong> 双重保障机制，将节点变化快速通知给服务消费者。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>心跳机制（保活）</strong>： <ul><li>服务提供者（比如订单服务）启动后，会启动一个定时任务，每隔 <strong>5 秒</strong> 向 Nacos Server 发送一个心跳包（&quot;我还活着&quot;）。</li><li>如果 Nacos Server 超过 <strong>15 秒</strong> 没收到心跳，就会把该实例标记为“不健康”。</li><li>如果超过 <strong>30 秒</strong> 还没收到，就会彻底把它从注册表中“剔除”。</li></ul></li><li><strong>动态感知（消费者如何知道节点挂了？）</strong>： <ul><li><strong>推（Push）</strong>：一旦 Nacos 注册表发生变化（比如某个节点挂了被剔除），Nacos 会立刻通过 UDP 协议将最新的实例列表推送给消费者。</li><li><strong>拉（Pull）</strong>：为了防止 UDP 丢包，消费者自己也会每隔 <strong>10 秒</strong> 定时向 Nacos 拉取最新的注册表信息，缓存在自己本地的 JVM 内存中。</li><li>这也是为什么当某个服务刚宕机时，消费者有时还会调用失败（因为心跳超时检测需要时间，且本地缓存还没更新），这时候通常依赖 Feign 的重试机制或 Sentinel 降级来兜底。</li></ul></li></ol><hr><h3 id="❓-面试官-sentinel-和以前的-hystrix-有什么区别-为什么要换-sentinel-【中级】" tabindex="-1">❓ 面试官：Sentinel 和以前的 Hystrix 有什么区别？为什么要换 Sentinel？【中级】 <a class="header-anchor" href="#❓-面试官-sentinel-和以前的-hystrix-有什么区别-为什么要换-sentinel-【中级】" aria-label="Permalink to “❓ 面试官：Sentinel 和以前的 Hystrix 有什么区别？为什么要换 Sentinel？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Hystrix 是老一代组件，目前已停止维护。Sentinel 是阿里开源的新一代流量防卫兵。相比 Hystrix 采用<strong>线程池隔离</strong>（极耗资源），Sentinel 默认采用<strong>信号量隔离</strong>（极轻量），且提供了极其丰富的限流规则和友好的<strong>可视化控制台页面</strong>。</p><p><strong>📝 详细对比核心点：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>Hystrix</th><th>Sentinel</th></tr></thead><tbody><tr><td><strong>隔离策略</strong></td><td><strong>线程池隔离</strong>（为每个依赖分配独立的线程池，优点是隔离彻底，缺点是线程上下文切换开销巨大，影响并发）</td><td><strong>信号量隔离</strong>（不创建新线程，只通过计数器限制并发数，轻量高效）</td></tr><tr><td><strong>流控粒度</strong></td><td>只能基于服务接口</td><td>支持基于 QPS、并发线程数、甚至具体的方法参数、系统整体 Load 进行限流</td></tr><tr><td><strong>熔断策略</strong></td><td>仅支持异常比例</td><td>支持慢调用比例、异常比例、异常数</td></tr><tr><td><strong>控制台控制</strong></td><td>简陋的 DashBoard</td><td>强大的控制台，支持实时监控、在线动态修改规则且立即生效</td></tr></tbody></table><hr><h3 id="❓-面试官-你们项目中是怎么使用-seata-解决分布式事务的-【高级】" tabindex="-1">❓ 面试官：你们项目中是怎么使用 Seata 解决分布式事务的？【高级】 <a class="header-anchor" href="#❓-面试官-你们项目中是怎么使用-seata-解决分布式事务的-【高级】" aria-label="Permalink to “❓ 面试官：你们项目中是怎么使用 Seata 解决分布式事务的？【高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我们在一些跨服务的强一致性场景（如“下单扣库存扣余额”）中使用了 Seata。主要采用它最无侵入的 <strong>AT 模式</strong>（两阶段提交的变种）。它的核心原理是<strong>拦截业务 SQL，自动生成反向回滚的 Undo Log，一旦某个微服务报错，利用 Undo Log 自动回滚所有节点的数据</strong>。</p><p><strong>📝 AT 模式底层流转（背诵模板）：</strong> 涉及三个核心角色：<strong>TC（事务协调者，Seata Server）</strong>、<strong>TM（事务管理器，你的主业务代码）</strong>、<strong>RM（资源管理器，各个微服务的数据库）</strong>。</p><ol><li><strong>一阶段（执行并提交本地事务）</strong>： <ul><li>主业务（TM）向 TC 申请开启一个全局事务，拿到一个全局 XID。</li><li>微服务（RM）在执行业务 SQL（比如 <code>update 库存 = 库存-1</code>）之前，Seata 会<strong>拦截</strong>这句 SQL。</li><li>Seata 去库里查出修改前的数据（Before Image），再查出修改后的数据（After Image），把它们拼装成一条 <strong>Undo Log</strong>，和业务数据<strong>在同一个本地数据库事务里提交</strong>。</li><li>此时，数据的锁已经被释放，极大提高了并发性能（这是它比传统 XA 事务快的原因）。</li></ul></li><li><strong>二阶段（决断：全局提交或回滚）</strong>： <ul><li><strong>情况 A（全成功）</strong>：TM 告诉 TC 大家都执行成功了。TC 通知所有 RM：可以收工了。RM 就会异步地去把刚才记录的 Undo Log 删掉。</li><li><strong>情况 B（有人报错）</strong>：比如积分服务报错了，抛出异常。TM 捕获到异常，向 TC 申请全局回滚。TC 通知所有参与过的 RM：开始回滚！RM 就会拿着一阶段记录的 Undo Log，生成一条反向补偿 SQL（比如把刚才扣的库存再加回去）并执行，从而实现数据最终一致性。</li></ul></li></ol>',25)])])}const S=r(e,[["render",a]]);export{h as __pageData,S as default};
